// Funções da Lista de Verificação
function addChecklistItem(isEdit = false) {
    const container = document.getElementById(isEdit ? 'edit-checklist-container' : 'checklist-container');
    const newItem = document.createElement('div');
    newItem.className = 'checklist-item flex items-center gap-2';
    
    const itemInput = document.createElement('input');
    itemInput.type = 'text';
    itemInput.className = 'flex-1 rounded-md border border-gray-300 px-3 py-2';
    itemInput.name = 'checklist_items[]';
    itemInput.placeholder = 'Digite uma etapa...';
    
    const checkboxDiv = document.createElement('div');
    checkboxDiv.className = 'flex items-center';
    
    const checkbox = document.createElement('input');
    checkbox.type = 'checkbox';
    checkbox.className = 'h-4 w-4 text-blue-600 rounded border-gray-300';
    checkbox.name = 'checklist_completed[]';
    
    const removeButton = document.createElement('button');
    removeButton.type = 'button';
    removeButton.className = 'btn btn-outline btn-sm';
    removeButton.innerHTML = '<i class="fas fa-trash"></i>';
    removeButton.onclick = function() { removeChecklistItem(this); };
    
    checkboxDiv.appendChild(checkbox);
    
    newItem.appendChild(itemInput);
    newItem.appendChild(checkboxDiv);
    newItem.appendChild(removeButton);
    container.appendChild(newItem);
}

function addChecklistItemEdit() {
    addChecklistItem(true);
}

function removeChecklistItem(button) {
    button.closest('.checklist-item').remove();
}

function getChecklistItems(formId) {
    const form = document.getElementById(formId);
    const items = [];
    const inputs = form.querySelectorAll('input[name="checklist_items[]"]');
    const checkboxes = form.querySelectorAll('input[name="checklist_completed[]"]');
    
    for (let i = 0; i < inputs.length; i++) {
        if (inputs[i].value.trim()) {
            items.push({
                text: inputs[i].value.trim(),
                completed: checkboxes[i].checked
            });
        }
    }
    return items;
}

function loadChecklistItems(items) {
    const container = document.getElementById('edit-checklist-container');
    container.innerHTML = '';
    
    if (items && items.length > 0) {
        items.forEach(item => {
            const newItem = document.createElement('div');
            newItem.className = 'checklist-item flex items-center gap-2';
            
            const itemInput = document.createElement('input');
            itemInput.type = 'text';
            itemInput.className = 'flex-1 rounded-md border border-gray-300 px-3 py-2';
            itemInput.name = 'checklist_items[]';
            itemInput.value = item.text;
            
            const checkboxDiv = document.createElement('div');
            checkboxDiv.className = 'flex items-center';
            
            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.className = 'h-4 w-4 text-blue-600 rounded border-gray-300';
            checkbox.name = 'checklist_completed[]';
            checkbox.checked = item.completed;
            
            checkboxDiv.appendChild(checkbox);
            
            const removeButton = document.createElement('button');
            removeButton.type = 'button';
            removeButton.className = 'btn btn-outline btn-sm';
            removeButton.innerHTML = '<i class="fas fa-trash"></i>';
            removeButton.onclick = function() { removeChecklistItem(this); };
            
            newItem.appendChild(itemInput);
            newItem.appendChild(checkboxDiv);
            newItem.appendChild(removeButton);
            container.appendChild(newItem);
        });
    } else {
        addChecklistItemEdit(); // Add one empty item by default
    }
}

// Funções para gerenciar responsáveis
function createResponsavelElement(containerId, index, selectedValue = '') {
    const div = document.createElement('div');
    div.className = 'responsavel-item d-flex align-items-center gap-2';

    const select = document.createElement('select');
    select.name = 'responsaveis[]';
    select.required = true;
    select.className = 'form-select flex-fill';

    // Buscar o template de usuários
    const templateSelect = document.getElementById('usuarios-template');

    // Copiar as opções do template
    if (templateSelect) {
        Array.from(templateSelect.options).forEach(opt => {
            select.add(new Option(opt.text, opt.value));
        });
    }

    if (selectedValue) {
        select.value = selectedValue;
    }

    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'btn btn-outline-danger btn-sm';
    button.innerHTML = '<i class="fas fa-trash"></i>';
    button.onclick = function() { removeResponsavel(this); };

    div.appendChild(select);
    div.appendChild(button);
    return div;
}

function addResponsavel() {
    const container = document.getElementById('responsaveis-container');
    const index = container.children.length;
    const element = createResponsavelElement('responsaveis-container', index);
    container.appendChild(element);
}

function removeResponsavel(button) {
    const div = button.closest('.responsavel-item');
    div.remove();
}

function addResponsavelEdit() {
    const container = document.getElementById('edit-responsaveis-container');
    const index = container.children.length;
    const element = createResponsavelElement('edit-responsaveis-container', index);
    container.appendChild(element);
}

// Event listeners para filtros e inicialização
document.addEventListener('DOMContentLoaded', function() {
    // Adicionar listeners para filtros em tempo real
    const filterInputs = ['filter_nome', 'filter_responsavel', 'filter_tipo', 'filter_status', 'filter_prioridade', 'filter_data_inicial', 'filter_data_final'];

    filterInputs.forEach(inputName => {
        const element = document.querySelector(`[name="${inputName}"]`);
        if (element) {
            element.addEventListener('input', filtrarProjetos);
            element.addEventListener('change', filtrarProjetos);
        }
    });

    // Configurar modals de Novo Projeto
    const modalNovoProjeto = document.getElementById('modalNovoProjeto');
    if (modalNovoProjeto) {
        // Inicializar quando o modal está sendo mostrado (antes de shown.bs.modal para evitar race condition)
        modalNovoProjeto.addEventListener('show.bs.modal', function () {
            const containerResp = document.getElementById('responsaveis-container');
            const containerChecklist = document.getElementById('checklist-container');

            // Resetar containers
            if (containerResp) {
                containerResp.innerHTML = '';
                addResponsavel(); // Adicionar um responsável inicial de forma síncrona
            }

            if (containerChecklist) {
                containerChecklist.innerHTML = '';
                addChecklistItem(); // Adicionar um checklist item inicial de forma síncrona
            }
        });

        // Limpar formulário quando o modal é fechado
        modalNovoProjeto.addEventListener('hidden.bs.modal', function () {
            const form = document.getElementById('formNovoProjeto');
            if (form) {
                // BUG-003: Limpar elementos dinâmicos antes de resetar o formulário
                const containerResp = document.getElementById('responsaveis-container');
                const containerChecklist = document.getElementById('checklist-container');

                if (containerResp) {
                    containerResp.innerHTML = '';
                }

                if (containerChecklist) {
                    containerChecklist.innerHTML = '';
                }

                // Resetar o formulário após limpar os containers
                form.reset();
            }
        });
    }

    // Configurar modal de Editar Projeto com a mesma lógica
    const modalEditarProjeto = document.getElementById('modalEditarProjeto');
    if (modalEditarProjeto) {
        modalEditarProjeto.addEventListener('hidden.bs.modal', function () {
            const form = document.getElementById('formEditarProjeto');
            if (form) {
                // BUG-003: Limpar elementos dinâmicos antes de resetar o formulário
                const containerResp = document.getElementById('edit-responsaveis-container');
                const containerChecklist = document.getElementById('edit-checklist-container');

                if (containerResp) {
                    containerResp.innerHTML = '';
                }

                if (containerChecklist) {
                    containerChecklist.innerHTML = '';
                }

                // Resetar o formulário após limpar os containers
                form.reset();
            }
        });
    }

    // Configurar modal de Novo Tipo de Serviço
    const modalNovoTipoServico = document.getElementById('modalNovoTipoServico');
    if (modalNovoTipoServico) {
        modalNovoTipoServico.addEventListener('hidden.bs.modal', function () {
            const form = document.getElementById('formNovoTipoServico');
            if (form) {
                form.reset();
                // Resetar estado do botão
                document.getElementById('btnSalvarTipo').disabled = false;
                document.getElementById('btnSalvarTipo').classList.remove('opacity-50', 'cursor-not-allowed');
                document.getElementById('tipoServiceAlert').classList.add('hidden');
            }
        });
    }
});

// ===== FUNÇÕES PARA ATUALIZAÇÃO DINÂMICA DA INTERFACE =====

/**
 * Atualiza os contadores de projetos por status
 */
function updateProjectCounters() {
    fetch(`${window.plannerConfig?.urls?.planner || window.location.href}?action=get_counters`)
        .then(response => response.json())
        .then(data => {
            if (data.status === 'success') {
                // Atualizar contadores por status
                const counters = data.counters;
                
                // Atualizar cards de status
                updateStatusCard('ativo', counters.ativo || 0);
                updateStatusCard('andamento', counters.andamento || 0);
                updateStatusCard('pausado', counters.pausado || 0);
                updateStatusCard('concluido', counters.concluido || 0);
                
                // Atualizar total de projetos
                const totalElement = document.querySelector('[data-total-projetos]');
                if (totalElement) {
                    totalElement.textContent = counters.total || 0;
                }
            }
        })
        .catch(error => {
            console.error('Erro ao atualizar contadores:', error);
        });
}

/**
 * Atualiza um card de status específico
 */
function updateStatusCard(status, count) {
    const statusMap = {
        'ativo': 'Ativo',
        'andamento': 'Em_andamento', 
        'pausado': 'Pausado',
        'concluido': 'Concluido'
    };
    
    const mappedStatus = statusMap[status] || status;
    const card = document.querySelector(`[data-status="${mappedStatus}"]`);
    
    if (card) {
        const countElement = card.querySelector('.display-4, .fs-1, h2, .project-count');
        if (countElement) {
            countElement.textContent = count;
        }
    }
}

/**
 * Adiciona um novo projeto à interface
 */
function addProjectToInterface(project) {
    // Adicionar à seção "Projetos por Tipo de Serviço"
    if (project.tipo_servico) {
        addProjectToTypeSection(project);
    }
    
    // Se o modal "Ver Todos os Projetos" estiver aberto, adicionar lá também
    const allProjectsModal = document.getElementById('modalTodosProjetos');
    if (allProjectsModal && allProjectsModal.classList.contains('show')) {
        addProjectToAllProjectsList(project);
    }
}

/**
 * Adiciona projeto à seção de tipo de serviço
 */
function addProjectToTypeSection(project) {
    const tipoNome = project.tipo_servico.nome;
    const tipoSlug = tipoNome.toLowerCase().replace(/[^a-z0-9]/g, '-');
    
    // Encontrar ou criar a seção do tipo
    let typeSection = document.querySelector(`[data-tipo="${tipoSlug}"]`);
    
    if (!typeSection) {
        // Criar nova seção de tipo se não existir
        createNewTypeSection(project.tipo_servico);
        typeSection = document.querySelector(`[data-tipo="${tipoSlug}"]`);
    }
    
    if (typeSection) {
        const projectsList = typeSection.querySelector('.projects-list, [id^="content-"]');
        if (projectsList) {
            const projectCard = createProjectCard(project);
            projectsList.appendChild(projectCard);
            
            // Atualizar contador do tipo
            updateTypeCounter(tipoSlug);
        }
    }
}

/**
 * Cria um card de projeto
 */
function createProjectCard(project) {
    const div = document.createElement('div');
    div.className = 'card p-3 border-start border-primary border-4 mb-3';
    div.setAttribute('data-project-id', project.id);
    
    const responsaveis = project.responsaveis ? 
        project.responsaveis.map(r => r.name).join(', ') : 
        'Sem responsáveis';
    
    const dataInicial = project.data_inicial ? 
        new Date(project.data_inicial).toLocaleDateString('pt-BR') : 
        'N/A';
    
    const dataConclusao = project.data_conclusao ? 
        new Date(project.data_conclusao).toLocaleDateString('pt-BR') : 
        'N/A';
    
    div.innerHTML = `
        <div class="d-flex justify-content-between align-items-start mb-3">
            <h4 class="fw-semibold fs-5 mb-0">${project.nome}</h4>
            <div class="d-flex gap-2">
                <span class="status-badge status-badge-${project.status.toLowerCase().replace(' ', '-')}">${project.status}</span>
                <span class="badge bg-warning text-dark">${project.prioridade}</span>
            </div>
        </div>
        <div class="row g-3 small text-muted mb-3">
            <div class="col-6"><strong>Responsáveis:</strong> ${responsaveis}</div>
            <div class="col-6"><strong>Tipo:</strong> ${project.tipo_servico ? project.tipo_servico.nome : 'N/A'}</div>
            <div class="col-6"><strong>Início:</strong> ${dataInicial}</div>
            <div class="col-6"><strong>Conclusão:</strong> ${dataConclusao}</div>
        </div>
        ${project.observacao ? `<p class="small text-muted mb-3"><strong>Observações:</strong> ${project.observacao}</p>` : ''}
        <div class="d-flex gap-2">
            <button onclick="editarProjeto('${project.id}')" class="btn btn-outline-primary btn-sm">
                <i class="fas fa-edit"></i> Editar
            </button>
            <button onclick="excluirProjeto('${project.id}')" class="btn btn-outline-danger btn-sm">
                <i class="fas fa-trash"></i> Excluir
            </button>
        </div>
    `;
    
    return div;
}

/**
 * Atualiza um projeto existente na interface
 */
function updateProjectInInterface(project) {
    // Encontrar e atualizar todos os cards do projeto
    const projectCards = document.querySelectorAll(`[data-project-id="${project.id}"]`);
    
    projectCards.forEach(card => {
        const newCard = createProjectCard(project);
        card.parentNode.replaceChild(newCard, card);
    });
    
    // Atualizar contadores de tipo se o tipo mudou
    updateTypeCounters();
}

/**
 * Remove um projeto da interface
 */
function removeProjectFromInterface(projectId) {
    const projectCards = document.querySelectorAll(`[data-project-id="${projectId}"]`);
    
    projectCards.forEach(card => {
        // Adicionar animação de saída
        card.style.transition = 'opacity 0.3s ease, transform 0.3s ease';
        card.style.opacity = '0';
        card.style.transform = 'translateX(-20px)';
        
        setTimeout(() => {
            card.remove();
        }, 300);
    });
    
    // Atualizar contadores de tipo
    setTimeout(() => {
        updateTypeCounters();
    }, 350);
}

/**
 * Atualiza contadores de todos os tipos
 */
function updateTypeCounters() {
    document.querySelectorAll('[data-tipo]').forEach(typeSection => {
        const tipoSlug = typeSection.getAttribute('data-tipo');
        updateTypeCounter(tipoSlug);
    });
}

/**
 * Atualiza contador de um tipo específico
 */
function updateTypeCounter(tipoSlug) {
    const typeSection = document.querySelector(`[data-tipo="${tipoSlug}"]`);
    if (typeSection) {
        const projectsList = typeSection.querySelector('.projects-list, [id^="content-"]');
        const projectCards = projectsList ? projectsList.querySelectorAll('[data-project-id]') : [];
        const count = projectCards.length;
        
        const counterElement = typeSection.querySelector('.project-count, .badge');
        if (counterElement) {
            counterElement.textContent = `${count} projeto${count !== 1 ? 's' : ''}`;
        }
    }
}

/**
 * Adiciona projeto à lista de todos os projetos (modal)
 */
function addProjectToAllProjectsList(project) {
    const projectsList = document.getElementById('filteredProjectsList');
    if (projectsList) {
        const projectCard = createProjectCard(project);
        projectsList.insertBefore(projectCard, projectsList.firstChild);
    }
}
